import os
import secrets
from urllib.parse import urlencode

import requests
from flask import Flask, redirect, request, session, url_for, jsonify

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

OIDC_ISSUER = os.environ.get("OIDC_ISSUER", "").rstrip("/")
AUTHORIZATION_ENDPOINT = os.environ.get("OIDC_AUTHORIZATION_ENDPOINT", f"{OIDC_ISSUER}/authorize")
CLIENT_ID = os.environ.get("OIDC_CLIENT_ID", "")
REDIRECT_URI = os.environ.get("OIDC_REDIRECT_URI", "http://localhost:5000/callback")
SCOPE = "openid"


@app.route("/")
def index():
    user = session.get("user")
    if user:
        return jsonify(
            {
                "authenticated": True,
                "user": user,
                "logout_url": url_for("logout", _external=True),
            }
        )
    return jsonify(
        {
            "authenticated": False,
            "login_url": url_for("login", _external=True),
        }
    )


@app.route("/login")
def login():
    state = secrets.token_urlsafe(32)
    session["oidc_state"] = state

    params = {
        "client_id": CLIENT_ID,
        "redirect_uri": REDIRECT_URI,
        "scope": SCOPE,
        "response_type": "id_token",
        "state": state,
    }
    authorization_url = f"{AUTHORIZATION_ENDPOINT}?{urlencode(params)}"
    return redirect(authorization_url, code=302)


@app.route("/callback")
def callback():
    error = request.args.get("error")
    if error:
        return jsonify(
            {
                "error": error,
                "error_description": request.args.get("error_description"),
            }
        ), 400

    state = request.args.get("state")
    expected_state = session.get("oidc_state")
    if not expected_state or state != expected_state:
        return jsonify({"error": "invalid_state"}), 400

    id_token = request.args.get("id_token")
    if not id_token:
        return jsonify(
            {
                "error": "missing_id_token",
                "detail": "For response_type=id_token, ensure the provider returns the token to this callback route.",
            }
        ), 400

    session.pop("oidc_state", None)
    session["user"] = {"id_token": id_token}
    return redirect(url_for("index"))


@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))


